import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    """
    {The algorithm selects the next node based on a dynamic priority score, which combines normalized inverse distance with a temporal decay factor influenced by how long the node has been unvisited, encouraging a mix of distance efficiency and coverage of less frequently visited nodes.}
    """
    if len(unvisited_nodes) == 0:
        return depot_node

    # Initialize parameters
    max_wait_time = 10  # Arbitrary max wait time to influence priority decay
    current_time = 0  # Simulated time or can be passed as an argument

    # Calculate inverse distance
    inverse_distances = {node: 1.0 / distance_matrix[current_node, node] if distance_matrix[current_node, node] > 0 else 0 for node in unvisited_nodes}

    # Simulate wait times (for example purposes, these should be dynamically tracked)
    last_visited_time = {node: current_time - np.random.randint(0, max_wait_time) for node in unvisited_nodes}

    # Calculate temporal decay factor
    decay_factor = {node: np.exp(-(current_time - last_visited_time[node]) / max_wait_time) for node in unvisited_nodes}

    # Calculate dynamic priority score
    dynamic_scores = {node: (inverse_distances[node] * 0.5) + (decay_factor[node] * 0.5) for node in unvisited_nodes}

    # Sort nodes based on dynamic scores in descending order
    sorted_nodes = sorted(dynamic_scores.items(), key=lambda x: x[1], reverse=True)

    # Choose the first available node not targeted by any truck
    next_node = None
    for node, _ in sorted_nodes:
        if node not in truck_nodes:
            next_node = node
            break

    # If no available suitable node, return None
    return next_node
